-- Exclui o banco de dados, se existir
DROP DATABASE IF EXISTS comercio;

-- Cria o banco de dados comercio, se ele não existir
CREATE DATABASE IF NOT EXISTS comercio;

-- Define o banco de dados como padrão
USE comercio;

-- Cria a tabela clientes, caso não exista
CREATE TABLE IF NOT EXISTS clientes(
  cpf            DECIMAL(11,0) NOT NULL PRIMARY KEY,
  nome           VARCHAR(100) NOT NULL,
  rg             DECIMAL(12,0) NOT NULL,
  data_nasc      VARCHAR(10) NOT NULL,
  sexo           VARCHAR(10) NOT NULL,
  cidade         VARCHAR(30) NOT NULL,
  estado         VARCHAR(2) NOT NULL,
  altura         DECIMAL(5,2) NOT NULL,
  peso           INT(3)  NOT NULL,
  tipo_sanguineo CHAR(3) NOT NULL
);

